import microcoapy as coapy

class IOTCoAPServer(coapy.CoAPServer):
    def __init__(self, port=5683):
        super().__init__(port)
        self.add_resource("/sensors/temp", TemperatureResource())
        self.add_resource("/actuators/light", LightActuatorResource())

class TemperatureResource(coapy.Resource):
    def get(self, request):
        # Simulate temperature reading
        temp = 25.0
        response = coapy.Response()
        response.payload = str(temp).encode('utf-8')
        return response

class LightActuatorResource(coapy.Resource):
    def put(self, request):
        if request.payload:
            state = request.payload.decode('utf-8').lower()
            if state == "on":
                # Simulate turning light on
                response = coapy.Response()
                response.code = coapy.Code.CHANGED
                return response
            elif state == "off":
                # Simulate turning light off
                response = coapy.Response()
                response.code = coapy.Code.CHANGED
                return response
        response = coapy.Response()
        response.code = coapy.Code.BAD_REQUEST
        return response

if __name__ == "__main__":
    server = IOTCoAPServer()
    server.start()